prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org rdfs:label ?orgName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "5a8e825c3a9a4049b67ab53c2ba7abc8") || 
         CONTAINS(LCASE(STR(?normalizedId)), "5a8e825c3a9a4049b67ab53c2ba7abc8") ||
         CONTAINS(LCASE(STR(?modelName)), "5a8e825c3a9a4049b67ab53c2ba7abc8"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# List all sequence flows with their source and target to understand the flow structure
SELECT ?edge ?edgeName ?sourceName ?targetName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_592364d0_3782_4d34_bcb3_5a37f16f70e4> .
  ?edge bbo:has_sourceRef ?source .
  ?edge bbo:has_targetRef ?target .
  OPTIONAL { ?edge bbo:name ?edgeName . }
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Get all nodes with their incoming and outgoing sequence flow counts to understand the structure
SELECT ?node ?nodeName ?type ?outgoingCount ?incomingCount WHERE {
  ?node tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_592364d0_3782_4d34_bcb3_5a37f16f70e4> .
  ?node a ?type .
  FILTER(?type IN (bboExt:ChoreographyTask, bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway, bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent))
  OPTIONAL { ?node bbo:name ?nodeName . }

  # Count outgoing flows
  {
    SELECT ?node (COUNT(?outEdge) AS ?outgoingCount) WHERE {
      ?node tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_592364d0_3782_4d34_bcb3_5a37f16f70e4> .
      OPTIONAL { ?outEdge bbo:has_sourceRef ?node . }
    }
    GROUP BY ?node
  }

  # Count incoming flows
  {
    SELECT ?node (COUNT(?inEdge) AS ?incomingCount) WHERE {
      ?node tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_592364d0_3782_4d34_bcb3_5a37f16f70e4> .
      OPTIONAL { ?inEdge bbo:has_targetRef ?node . }
    }
    GROUP BY ?node
  }
}
ORDER BY ?nodeName
LIMIT 50
